function getWuXingRelation(yaoWx, gongWx) {
  if (yaoWx === gongWx) return "比和";
  if (SHENG[yaoWx] === gongWx) return "生我";
  if (SHENG[gongWx] === yaoWx) return "我生";
  if (KE[yaoWx] === gongWx) return "尅我";
  if (KE[gongWx] === yaoWx) return "我尅";
  return "比和";
}
function wuXingToLiuQin(yaoWuXing, gongWuXing) {
  const relation = getWuXingRelation(yaoWuXing, gongWuXing);
  switch (relation) {
    case "比和":
      return "兄弟";
    case "生我":
      return "父母";
    case "我生":
      return "子孙";
    case "尅我":
      return "官鬼";
    case "我尅":
      return "妻财";
    default:
      return "兄弟";
  }
}
function rotateList(list, start) {
  const idx = list.indexOf(start);
  if (idx === -1) return [...list];
  return [...list.slice(idx), ...list.slice(0, idx)];
}
function rotateListByIndex(list, startIndex) {
  const idx = startIndex % list.length;
  return [...list.slice(idx), ...list.slice(0, idx)];
}
function solarToLunar(year, month, day, hour = 0) {
  let adjustedDay = day;
  let adjustedMonth = month;
  let adjustedYear = year;
  if (hour >= 23) {
    const date = new Date(year, month - 1, day + 1);
    adjustedYear = date.getFullYear();
    adjustedMonth = date.getMonth() + 1;
    adjustedDay = date.getDate();
  }
  const solar = SolarDay.fromYmd(adjustedYear, adjustedMonth, adjustedDay);
  const lunar = solar.getLunarDay();
  const lunarMonth = lunar.getLunarMonth();
  const sixtyCycleDay = solar.getSixtyCycleDay();
  const yearGZ = sixtyCycleDay.getYear().getName();
  const monthGZ = sixtyCycleDay.getMonth().getName();
  const dayGZ = sixtyCycleDay.getSixtyCycle().getName();
  const hourGZ = SolarTime.fromYmdHms(year, month, day, hour, 0, 0).getSixtyCycleHour().getSixtyCycle().getName();
  return {
    year: lunarMonth.getLunarYear().getYear(),
    month: Math.abs(lunarMonth.getMonthWithLeap()),
    day: lunar.getDay(),
    isLeap: lunarMonth.isLeap(),
    yearGanZhi: parseGanZhi(yearGZ),
    monthGanZhi: parseGanZhi(monthGZ),
    dayGanZhi: parseGanZhi(dayGZ),
    hourGanZhi: parseGanZhi(hourGZ)
  };
}
